      ) : (
        <ul>
          {cartItems.map(item => (
            <li key={item.id} className="flex justify-between items-center mb-4">
              <span>{item.title}</span>
              <button onClick={() => removeFromCart(item.id)} className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition">
                Remove
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default Cart;

