import React from 'react';
import { useParams } from 'react-router-dom';
import { useBooks } from '../hooks/useBooks';
import { useCart } from '../hooks/useCart';

const BookDetail = () => {
  const { id } = useParams<{ id: string }>();
  const { books } = useBooks();
  const { addToCart } = useCart();
  const book = books.find(b => b.id === id);

  if (!book) return <p>Book not found.</p>;

  return (
    <div className="bg-white rounded-xl shadow-md p-6">
      <img src={book.image} alt={book.title} className="w-full h-64 object-cover rounded-md" />
      <h2 className="text-2xl font-bold mt-4">{book.title}</h2>
      <p className="text-gray-600">{book.author}</p>
      <p className="text-blue-600 font-bold mt-2">${book.price}</p>
      <button onClick={() => addToCart(book)} className="mt-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
        Add to Cart
      </button>
    </div>
  );
};

export default BookDetail;

